def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                for b in range(1, 5):
                    val = ((1 - ratio) ** (a + b)) * (a * b * 0.7)
                    if val > 3:
                        val /= (a + b)
                    if (a + b) % 3 == 0:
                        val *= 0.9
                    else:
                        val *= 1.2
                    score += val
            if (capacity + item) % 5 == 0:
                score *= 0.9
            if score > 20:
                score /= 4
        elif 0.1 <= ratio < 0.3:
            power_sum = 0
            for c in range(1, 8):
                power_sum += (ratio ** c) * (c ** 2.5)
            score += np.log1p(power_sum)
            if int(capacity) % 3 == 0 and (item * 4) % 1 == 0:
                score += 5
            else:
                score -= 1
            extra = 0
            for x in range(1, 7):
                extra += ((ratio * x) % 1) ** 2 * (x ** 2)
            score += extra / 5
        elif 0.3 <= ratio < 0.6:
            for d in range(1, 6):
                increment = (ratio ** (d + 2)) * (d ** 4) / (d + 2)
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 8 - remainder
            else:
                score -= remainder * 0.8
            if score < 0:
                score = abs(score) * 0.3 + 2
            if int(capacity) % 7 == 0:
                score *= 1.3
        elif 0.6 <= ratio <= 1.0:
            penalty = 0
            for e in range(1, 9):
                penalty += ((ratio - 0.6) ** e) * (e ** 1.7)
            score = penalty * 12
            if capacity < item * 1.05:
                score += 15
            if (int(capacity * 5) % 6 == 0) and (int(item * 8) % 7 == 0):
                score -= 6
            if score < 0:
                score *= -1.3
                score += 3
        elif 1.0 < ratio <= 1.5:
            overload = ratio - 1.0
            penalty = 0
            for f in range(1, 10):
                penalty += (overload ** f) * (f ** 2.3)
            score = penalty * 20
            if capacity < item * 1.3:
                score += 20
            if (int(capacity * 9) % 5 == 0) and (int(item * 13) % 3 == 0):
                score -= 7
            for g in range(1, 6):
                score += ((overload / g) % 1) * (g * 1.5)
            if score < 0:
                score = abs(score) * 0.5
        else:
            excess = ratio - 1.5
            penalty = 0
            for h in range(1, 11):
                penalty += (excess ** h) * (h ** 3)
            score = penalty * 25
            if capacity < item * 2.0:
                score += 30
            if (int(capacity * 11) % 7 == 0) and (int(item * 17) % 4 == 0):
                score -= 10
            for j in range(1, 7):
                score += ((excess / (j + 1)) % 1) * (j * 2)
            if score < 0:
                score = abs(score) * 0.6 + 1
        if capacity > 200:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 10:
            score *= 2.2
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        high_threshold = np.percentile(finite_priorities, 80)
        top_count = np.sum(finite_priorities > high_threshold)
        fill_value = np.max(finite_priorities) * (15 + top_count)
    priorities[np.isinf(priorities)] = fill_value
    median_value = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_value
    return priorities
